            RekenBvKey.OUD_BEDRIJFSVOORHEFFING_ACHTERSTAL_WINST_PREMIE_KEY
    };

    private static final ContextKey[] ADDITIONS = {
            RekenRszKey.WERKBONUS_LAGE_LONEN_KEY,
            RekenRszKey.WERKBONUS_HEEL_LAGE_LONEN_KEY,
            RekenRszKey.VERMINDERING_HERSTRUCTERING_KEY,
            RekenRszKey.WERKBONUS_GEPENSIONEERD_KEY,
            RekenBvKey.VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_KEY,
            RekenBvKey.VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_B_KEY,
            RekenBvKey.VLAAMSE_VERMINDERING_BEDRIJFSVOORHEFFING_KEY};

    @Override
    protected boolean execute(RekenContext context) {
        LoonElementManager manager = context.getUnchecked(RekenChainKey.LOONELEMENT_MANAGER_KEY);
        Collection<LoonElement> loonElementen = manager.getPersoonsElementen();
        berekenNettoLoon(loonElementen);
        return CONTINUE_PROCESSING;
    }

    public void berekenNettoLoon(Collection<LoonElement> loonElementen) {
        for (LoonElement element : loonElementen) {
            Money nettoLoon = Money.ZERO;
            boolean isAftrokEnkelvoudigVakantiegeld = element.getAardKodeExtensie().behoortTotGroep(LooncodeGroepKeyStrings.AFTROK_EVUD_VWG_KEY);
            if (!isAftrokEnkelvoudigVakantiegeld) {
                nettoLoon = nettoLoon.add(element.getPropertyMoney(RekenBrutoKey.BRUTO_MAANDLOON_KEY));
            }
            for (ContextKey addition : ADDITIONS) {
                nettoLoon = nettoLoon.add(element.getPropertyMoney(addition));
            }
            for (ContextKey subtraction : SUBTRACTIONS) {
                nettoLoon = nettoLoon.subtract(element.getPropertyMoney(subtraction));
            }
            element.putProperty(RekenNettoKey.NETTO_KEY, nettoLoon);
        }
    }
}
